// Input: All rows from Google Sheet
// Output: Rows starting from the first row where "Offboarded Links" is blank

let rows = items.map(item => item.json);

// Find the index of the first row where "Offboarded Links" is blank or empty
let startIndex = rows.findIndex(row => 
    row["Offboarded Links"] === "" || row["Offboarded Links"] === null || row["Offboarded Links"] === undefined
);

// अगर कोई match नहीं मिला तो खाली array return करो
if (startIndex === -1) {
    return [];
}

// उस row से लेकर बाकी सभी rows return करो
let filteredRows = rows.slice(startIndex);

// Output को n8n के लिए format करो
return filteredRows.map(row => ({ json: row }));

// Get input domains
const inputItems = $input.all();
const domains = inputItems.map(item => {
  try {
    const url = new URL(item.json["Website URLs"]);
    return url.hostname.replace(/^www\./, ""); // Remove www.
  } catch (e) {
    return null;
  }
}).filter(Boolean);

// Get HTML Data
const htmlData = $('Fetch PBN Site HTML').first().json.data;

// Check matches
let matched = [];
for (const domain of domains) {
  if (htmlData.includes(domain)) {
    matched.push(domain);
  }
}

// Return result
if (matched.length > 0) {
  return matched.map(d => ({ json: { matched_domain: d } }));
} else {
  return [{ json: { matched_domain: 0 } }];
}
